mapper.update:
UPDATE HOSPITAL_UPDATE_REQUEST
SET STATUS = #{status},
PROCESSED_AT = SYSDATE,
REJECT_REASON = #{rejectReason}
WHERE REQUEST_ID = #{requestId}

UPDATE HOSPITAL
SET OPEN_TIME = #{openTime},
CLOSE_TIME = #{closeTime},
BREAK_TIME = #{lunchTime},
CLOSED_DAYS = #{holiday}
WHERE HOSPITAL_ID = #{hospitalId}

UPDATE HOSPITAL
SET STATUS = 'CLOSED', NOTE = 'DELETE_PENDING', UPDATED_AT = SYSTIMESTAMP
WHERE HOSPITAL_ID = #{hospitalId}

UPDATE HOSPITAL
SET STATUS = 'OPEN', NOTE = NULL, UPDATED_AT = SYSTIMESTAMP
WHERE HOSPITAL_ID = #{hospitalId}
